"""Модель глобальной конфигурации приложения (app.ini)."""from __future__ import annotationsfrom dataclasses import dataclassfrom src.core.models.core_config import CoreConfigfrom src.modules.llm_providers.module import LLMProvidersConfigfrom src.modules.yandex_ocr.module import YandexOCRConfig@dataclass(frozen=True)class AppConfig:    """Полная модель конфигурации приложения (источник истины для app.ini)."""    core: CoreConfig    llm_providers: LLMProvidersConfig    yandex_ocr: YandexOCRConfig    @classmethod    def default(cls) -> AppConfig:        """Конфиг по умолчанию для генерации шаблона app.ini."""        return cls(            core=CoreConfig(),            llm_providers=LLMProvidersConfig(),            yandex_ocr=YandexOCRConfig(),        )